import { common } from '@kit.AbilityKit';
import { AppStorage } from '@kit.ArkUI';
import { SafetyRepository } from '../services/SafetyRepository';
import { DashboardCalculator } from '../services/DashboardCalculator';
import { IdGen } from '../services/IdGen';
import {
  SafetyRecord, RiskItem, PatrolCheckin, EmergencyContact,
  RecordDraft, RiskDraft, CheckinDraft, ContactDraft,
  RiskStatus, ValidationResult, DashboardData,
} from '../model/Models';

const PK_RECORDS = 'pk_records';
const PK_RISKS = 'pk_risks';
const PK_CONTACTS = 'pk_contacts';
const PK_POINTS = 'pk_points';
const PK_CHECKINS = 'pk_checkins';
const PK_DASHBOARD = 'pk_dashboard';
const PK_DASHBOARD_PERIOD = 'pk_dashboard_period';
const PK_SELECTED_ROUTE = 'pk_selected_route';

export class AppController {
  private static _inst: AppController | null = null;
  readonly repo: SafetyRepository;
  private period: string = 'week';
  private selectedRouteId: string = '';

  private constructor(ctx?: common.Context) {
    this.repo = new SafetyRepository(ctx);
  }

  static instance(): AppController {
    if (AppController._inst === null) {
      AppController._inst = new AppController();
    }
    return AppController._inst;
  }

  static init(ctx: common.Context): Promise<void> {
    const inst = AppController.instanceWithContext(ctx);
    return inst.load();
  }

  private static instanceWithContext(ctx: common.Context): AppController {
    if (AppController._inst === null) {
      AppController._inst = new AppController(ctx);
    }
    return AppController._inst;
  }

  async load(): Promise<void> {
    await this.repo.init();
    this.period = (AppStorage.get<string>(PK_DASHBOARD_PERIOD)) ?? 'week';
    if (this.repo.routes.length > 0) {
      this.selectedRouteId = this.repo.routes[0].id;
    }
    this.emitAll();
  }

  private emitAll(): void {
    AppStorage.setOrCreate<SafetyRecord[]>(PK_RECORDS, this.repo.records);
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    AppStorage.setOrCreate<EmergencyContact[]>(PK_CONTACTS, this.repo.contacts);
    AppStorage.setOrCreate<string>(PK_SELECTED_ROUTE, this.selectedRouteId);
    AppStorage.setOrCreate<string>(PK_DASHBOARD_PERIOD, this.period);
    this.emitDashboard();
  }

  private emitDashboard(): void {
    const data: DashboardData = DashboardCalculator.compute(
      this.repo.records, this.repo.risks, this.repo.points,
      this.repo.checkins, this.period, this.selectedRouteId);
    AppStorage.setOrCreate<DashboardData>(PK_DASHBOARD, data);
  }
  ...
}
