saveRecord(d: RecordDraft, id?: string): ValidationResult {
  const v = this.validateRecord(d);
  if (!v.valid) return v;
  const now: number = Date.now();
  if (id !== undefined && id.length > 0) {
    const existing = this.repo.getRecord(id);
    if (existing === null) return { valid: false, message: '记录不存在' };
    const updated: SafetyRecord = {
      id: existing.id,
      title: d.title,
      category: d.category,
      datetime: d.datetime,
      location: d.location,
      description: d.description,
      photos: d.photos,
      createdAt: existing.createdAt,
      updatedAt: now,
    };
    this.repo.updateRecord(existing.id, updated);
  } else {
    const rec: SafetyRecord = {
      id: IdGen.next('rec'),
      title: d.title,
      category: d.category,
      datetime: d.datetime,
      location: d.location,
      description: d.description,
      photos: d.photos,
      createdAt: now,
      updatedAt: now,
    };
    this.repo.addRecord(rec);
  }
  this.repo.persistRecords();
  AppStorage.setOrCreate<SafetyRecord[]>(PK_RECORDS, this.repo.records);
  this.emitDashboard();
  return { valid: true, message: '已保存' };
}
