```arkts
import {
  SafetyRecord, RiskItem, PatrolPoint, PatrolCheckin,
  DashboardData, DashboardTrendPoint, RiskLevel,
} from '../model/Models';

const DAY_MS = 24 * 60 * 60 * 1000;

export class DashboardCalculator {
  static compute(
    records: SafetyRecord[],
    risks: RiskItem[],
    points: PatrolPoint[],
    checkins: PatrolCheckin[],
    period: string,
    selectedRouteId: string,
  ): DashboardData {
    const span: number = period === 'month' ? 30 : 7;
    const now: number = Date.now();
    const startOfDay: number = Math.floor(now / DAY_MS) * DAY_MS;

    // patrol completion (today, selected route)
    const routePointIds: string[] = selectedRouteId.length > 0
      ? points.filter((p: PatrolPoint): boolean => p.routeId === selectedRouteId).map((p: PatrolPoint): string => p.id)
      : points.map((p: PatrolPoint): string => p.id);
    const todayStart: number = startOfDay;
    const checkedToday: Set<string> = new Set<string>();
    for (const c of checkins) {
      if (c.time >= todayStart && c.time < todayStart + DAY_MS) {
        checkedToday.add(c.pointId);
      }
    }
    let patrolCompletionRate = 0;
    if (routePointIds.length > 0) {
      let done = 0;
      for (const pid of routePointIds) {
        if (checkedToday.has(pid)) done++;
      }
      patrolCompletionRate = Math.round((done / routePointIds.length) * 100);
    }

    // risk resolution
    const closed = risks.filter((r: RiskItem): boolean => r.status === 'closed').length;
    const riskResolutionRate = risks.length > 0 ? Math.round((closed / risks.length) * 100) : 0;

    // overdue
    const overdueRisksCount = risks.filter((r: RiskItem): boolean =>
      r.status !== 'closed' && r.deadline > 0 && r.deadline < now).length;

    // trend
    const trend: DashboardTrendPoint[] = [];
    for (let i = span - 1; i >= 0; i--) {
      const dayStart = startOfDay - i * DAY_MS;
      const dayEnd = dayStart + DAY_MS;
      let rc = 0;
      for (const rec of records) {
        if (rec.createdAt >= dayStart && rec.createdAt < dayEnd) rc++;
      }
      let rk = 0;
      for (const ris of risks) {
        if (ris.createdAt >= dayStart && ris.createdAt < dayEnd) rk++;
      }
      const d = new Date(dayStart);
      const label = `${d.getMonth() + 1}-${d.getDate()}`;
      trend.push({ dateLabel: label, records: rc, risks: rk });
    }

    // level distribution
    const dist: Record<string, number> = { low: 0, medium: 0, high: 0, critical: 0 };
    for (const ris of risks) {
      dist[ris.level] = (dist[ris.level] ?? 0) + 1;
    }

    // top risks: open, by level weight then recency
    const weight: Record<string, number> = { critical: 4, high: 3, medium: 2, low: 1 };
    const open = risks.filter((r: RiskItem): boolean => r.status !== 'closed')
      .slice()
      .sort((a: RiskItem, b: RiskItem): number => {
        const w = (weight[b.level] ?? 0) - (weight[a.level] ?? 0);
        if (w !== 0) return w;
        return b.createdAt - a.createdAt;
      });
    const topRisks = open.slice(0, 5);

    return {
      period,
      patrolCompletionRate,
      riskResolutionRate,
      overdueRisksCount,
      totalRecordsCount: records.length,
      trend,
      riskLevelDistribution: dist,
      topRisks,
    };
  }
}
```

