    this.repo.updateRecord(id, updated);
  } else {
    const rec: SafetyRecord = {
      id: IdGen.next('rec'), title: d.title, category: d.category, datetime: d.datetime,
      location: d.location, description: d.description, photos: d.photos,
      createdAt: now, updatedAt: now,
    };
    this.repo.addRecord(rec);
  }
