// Simple id generator for entity records.
// Uses Date.now() + random suffix; collision-safe enough for a local-only app.

export class IdGen {
  static next(prefix: string): string {
    const t: string = Date.now().toString(36);
    const r: string = Math.floor(Math.random() * 1000000).toString(36);
    return `${prefix}_${t}_${r}`;
  }
}

