// Persistence + in-memory cache for all Pinankou user data.
// Offline-first; backed by HarmonyOS Preferences (one store: pinankou_store).
// Each collection is serialized as a JSON string.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import {
  SafetyRecord,
  RiskItem,
  PatrolRoute,
  PatrolPoint,
  PatrolCheckin,
  EmergencyContact,
  RecordCategory,
  RiskLevel,
  RiskStatus,
  ContactGroup,
} from '../model/Models';

const STORE_NAME: string = 'pinankou_store';
const K_RECORDS: string = 'records';
const K_RISKS: string = 'risks';
const K_CONTACTS: string = 'contacts';
const K_ROUTES: string = 'routes';
const K_POINTS: string = 'points';
const K_CHECKINS: string = 'checkins';

type ObjMap = Record<string, Object>;

function toStringArray(v: Object | undefined): string[] {
  const out: string[] = [];
  if (v === undefined || v === null) {
    return out;
  }
  const arr: Object[] = v as Object[];
  for (let i = 0; i < arr.length; i++) {
    out.push(arr[i] as string);
  }
  return out;
}

function parseRecords(raw: string): SafetyRecord[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: SafetyRecord[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      title: o['title'] as string,
      category: o['category'] as RecordCategory,
      datetime: o['datetime'] as number,
      location: o['location'] as string,
      description: o['description'] as string,
      photos: toStringArray(o['photos']),
      createdAt: o['createdAt'] as number,
      updatedAt: o['updatedAt'] as number,
    });
  }
  return out;
}

function parseRisks(raw: string): RiskItem[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: RiskItem[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      title: o['title'] as string,
      level: o['level'] as RiskLevel,
      location: o['location'] as string,
      description: o['description'] as string,
      assignee: o['assignee'] as string,
      deadline: o['deadline'] as number,
      status: o['status'] as RiskStatus,
      progress: o['progress'] as number,
      progressNote: o['progressNote'] as string,
      photos: toStringArray(o['photos']),
      createdAt: o['createdAt'] as number,
      updatedAt: o['updatedAt'] as number,
    });
  }
  return out;
}

function parseContacts(raw: string): EmergencyContact[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: EmergencyContact[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      name: o['name'] as string,
      role: o['role'] as string,
      group: o['group'] as ContactGroup,
      phone: o['phone'] as string,
    });
  }
  return out;
}

function parseRoutes(raw: string): PatrolRoute[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: PatrolRoute[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      name: o['name'] as string,
      pointIds: toStringArray(o['pointIds']),
    });
  }
  return out;
}

function parsePoints(raw: string): PatrolPoint[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: PatrolPoint[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      routeId: o['routeId'] as string,
      name: o['name'] as string,
      location: o['location'] as string,
      order: o['order'] as number,
    });
  }
  return out;
}

function parseCheckins(raw: string): PatrolCheckin[] {
  const arr: ObjMap[] = JSON.parse(raw) as ObjMap[];
  const out: PatrolCheckin[] = [];
  for (let i = 0; i < arr.length; i++) {
    const o: ObjMap = arr[i];
    out.push({
      id: o['id'] as string,
      pointId: o['pointId'] as string,
      routeId: o['routeId'] as string,
      time: o['time'] as number,
      location: o['location'] as string,
      note: o['note'] as string,
      isAbnormal: o['isAbnormal'] as boolean,
      photos: toStringArray(o['photos']),
      createdAt: o['createdAt'] as number,
    });
  }
  return out;
}

export class SafetyRepository {
  private store: preferences.Preferences | null = null;
  private readonly ctx: common.Context | null;

  records: SafetyRecord[] = [];
  risks: RiskItem[] = [];
  contacts: EmergencyContact[] = [];
  routes: PatrolRoute[] = [];
  points: PatrolPoint[] = [];
  checkins: PatrolCheckin[] = [];

  constructor(ctx?: common.Context) {
    this.ctx = ctx !== undefined ? ctx : null;
  }

  async init(): Promise<void> {
    if (this.ctx !== null) {
      try {
        this.store = await preferences.getPreferences(this.ctx, STORE_NAME);
      } catch (e) {
        this.store = null;
      }
    }
    this.records = await this.read(K_RECORDS, parseRecords);
    this.risks = await this.read(K_RISKS, parseRisks);
    this.contacts = await this.read(K_CONTACTS, parseContacts);
    this.routes = await this.read(K_ROUTES, parseRoutes);
    this.points = await this.read(K_POINTS, parsePoints);
    this.checkins = await this.read(K_CHECKINS, parseCheckins);
    if (this.routes.length === 0 && this.points.length === 0) {
      this.seedDefaultRoute();
      await this.persistRoutes();
      await this.persistPoints();
    }
  }

  private async read<T>(key: string, mapper: (raw: string) => T[]): Promise<T[]> {
    if (this.store === null) {
      return [];
    }
    try {
      const raw: Object = await this.store.get(key, '[]');
      const text: string = raw as string;
      if (text.length === 0) {
        return [];
      }
      return mapper(text);
    } catch (e) {
      return [];
    }
  }

  private async write(key: string, json: string): Promise<void> {
    if (this.store === null) {
      return;
    }
    try {
      await this.store.put(key, json);
      await this.store.flush();
    } catch (e) {
      // best-effort persistence; in-memory state already updated
    }
  }

  // ---- Records ----
  getRecord(id: string): SafetyRecord | null {
    for (let i = 0; i < this.records.length; i++) {
      if (this.records[i].id === id) {
        return this.records[i];
      }
    }
    return null;
  }

  addRecord(rec: SafetyRecord): void {
    this.records.unshift(rec);
  }

  updateRecord(id: string, rec: SafetyRecord): void {
    for (let i = 0; i < this.records.length; i++) {
      if (this.records[i].id === id) {
        this.records[i] = rec;
        return;
      }
    }
  }

  deleteRecord(id: string): void {
    this.records = this.records.filter((r: SafetyRecord): boolean => r.id !== id);
  }

  async persistRecords(): Promise<void> {
    await this.write(K_RECORDS, JSON.stringify(this.records));
  }

  // ---- Risks ----
  getRisk(id: string): RiskItem | null {
    for (let i = 0; i < this.risks.length; i++) {
      if (this.risks[i].id === id) {
        return this.risks[i];
      }
    }
    return null;
  }

  addRisk(risk: RiskItem): void {
    this.risks.unshift(risk);
  }

  updateRisk(id: string, risk: RiskItem): void {
    for (let i = 0; i < this.risks.length; i++) {
      if (this.risks[i].id === id) {
        this.risks[i] = risk;
        return;
      }
    }
  }

  deleteRisk(id: string): void {
    this.risks = this.risks.filter((r: RiskItem): boolean => r.id !== id);
  }

  async persistRisks(): Promise<void> {
    await this.write(K_RISKS, JSON.stringify(this.risks));
  }

  // ---- Contacts ----
  getContact(id: string): EmergencyContact | null {
    for (let i = 0; i < this.contacts.length; i++) {
      if (this.contacts[i].id === id) {
        return this.contacts[i];
      }
    }
    return null;
  }

  addContact(c: EmergencyContact): void {
    this.contacts.push(c);
  }

  updateContact(id: string, c: EmergencyContact): void {
    for (let i = 0; i < this.contacts.length; i++) {
      if (this.contacts[i].id === id) {
        this.contacts[i] = c;
        return;
      }
    }
  }

  deleteContact(id: string): void {
    this.contacts = this.contacts.filter((c: EmergencyContact): boolean => c.id !== id);
  }

  async persistContacts(): Promise<void> {
    await this.write(K_CONTACTS, JSON.stringify(this.contacts));
  }

  // ---- Patrol ----
  pointsOfRoute(routeId: string): PatrolPoint[] {
    return this.points
      .filter((p: PatrolPoint): boolean => p.routeId === routeId)
      .sort((a: PatrolPoint, b: PatrolPoint): number => a.order - b.order);
  }

  addCheckin(c: PatrolCheckin): void {
    this.checkins.unshift(c);
  }

  async persistCheckins(): Promise<void> {
    await this.write(K_CHECKINS, JSON.stringify(this.checkins));
  }

  async persistRoutes(): Promise<void> {
    await this.write(K_ROUTES, JSON.stringify(this.routes));
  }

  async persistPoints(): Promise<void> {
    await this.write(K_POINTS, JSON.stringify(this.points));
  }

  // Structural default route (config, not user record data).
  private seedDefaultRoute(): void {
    const routeId: string = 'route_default';
    const defs: Array<[string, string, string]> = [
      ['pt_gate', '大门出入口', '园区1号门'],
      ['pt_fire', '消防控制室', 'A栋1层'],
      ['pt_park', '地下停车场', 'B2层'],
      ['pt_warehouse', '危化品仓库', 'C区'],
    ];
    const pointIds: string[] = [];
    for (let i = 0; i < defs.length; i++) {
      const d: [string, string, string] = defs[i];
      this.points.push({
        id: d[0],
        routeId: routeId,
        name: d[1],
        location: d[2],
        order: i,
      });
      pointIds.push(d[0]);
    }
    this.routes.push({
      id: routeId,
      name: '园区日常巡检路线',
      pointIds: pointIds,
    });
  }
}

