// Dialer adapter. call.makeCall opens the system dialer UI; it does NOT require
// the system-only PLACE_CALL permission, so it is the correct third-party path.

import { call } from '@kit.TelephonyKit';
import { common } from '@kit.AbilityKit';

export class PhoneService {
  static async dial(ctx: common.Context, phone: string): Promise<boolean> {
    if (!phone || phone.length === 0) {
      return false;
    }
    try {
      await call.makeCall(ctx, phone);
      return true;
    } catch (e) {
      return false;
    }
  }
}

