// Central state machine for 平安扣 Pinankou.
// Owns the repository, validates drafts, advances the risk state machine,
// and pushes reactive snapshots into AppStorage so pages can @StorageLink.
// Navigation/surface routing lives in the Index shell (visual phase); this
// controller is data + behavior only.

import { common } from '@kit.AbilityKit';
import { SafetyRepository } from '../services/SafetyRepository';
import { DashboardCalculator } from '../services/DashboardCalculator';
import { IdGen } from '../services/IdGen';
import { PhoneService } from '../services/PhoneService';
import {
  SafetyRecord,
  RiskItem,
  PatrolRoute,
  PatrolPoint,
  PatrolCheckin,
  EmergencyContact,
  RecordDraft,
  RiskDraft,
  CheckinDraft,
  ContactDraft,
  ValidationResult,
  DashboardData,
  ActivityEntry,
  ContactGroup,
} from '../model/Models';
import {
  RECORD_CATEGORY_OPTIONS,
  CONTACT_GROUP_OPTIONS,
} from '../model/Labels';

// AppStorage keys (consumed by pages via @StorageLink / @StorageProp).
export const PK_RECORDS: string = 'pk_records';
export const PK_RISKS: string = 'pk_risks';
export const PK_CONTACTS: string = 'pk_contacts';
export const PK_ROUTES: string = 'pk_routes';
export const PK_POINTS: string = 'pk_points';
export const PK_CHECKINS: string = 'pk_checkins';
export const PK_SELECTED_ROUTE: string = 'pk_selected_route';
export const PK_DASHBOARD_PERIOD: string = 'pk_dashboard_period';
export const PK_DASHBOARD: string = 'pk_dashboard';
export const PK_HOME_ACTIVITY: string = 'pk_home_activity';
export const PK_HOME_PENDING_RISKS: string = 'pk_home_pending_risks';
export const PK_HOME_PATROL_PROGRESS: string = 'pk_home_patrol_progress';

const DEFAULT_PERIOD: string = 'week';

export class AppController {
  private static inst: AppController | null = null;

  readonly repo: SafetyRepository;
  private readonly ctx: common.Context | null;
  private period: string = DEFAULT_PERIOD;
  private selectedRouteId: string = '';

  private constructor(ctx?: common.Context) {
    this.ctx = ctx !== undefined ? ctx : null;
    this.repo = new SafetyRepository(ctx);
  }

  static instance(): AppController {
    if (AppController.inst === null) {
      AppController.inst = new AppController();
    }
    return AppController.inst;
  }

  static init(ctx: common.Context): Promise<void> {
    const c: AppController = AppController.instanceWith(ctx);
    return c.load();
  }

  private static instanceWith(ctx: common.Context): AppController {
    if (AppController.inst === null) {
      AppController.inst = new AppController(ctx);
    }
    return AppController.inst;
  }

  async load(): Promise<void> {
    await this.repo.init();
    const storedPeriod: string | undefined = AppStorage.get<string>(PK_DASHBOARD_PERIOD);
    this.period = storedPeriod !== undefined && storedPeriod.length > 0 ? storedPeriod : DEFAULT_PERIOD;
    this.selectedRouteId = this.repo.routes.length > 0 ? this.repo.routes[0].id : '';
    this.emitAll();
  }

  // ---- Reactive snapshot emission ----
  private emitAll(): void {
    AppStorage.setOrCreate<SafetyRecord[]>(PK_RECORDS, this.repo.records);
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    AppStorage.setOrCreate<EmergencyContact[]>(PK_CONTACTS, this.repo.contacts);
    AppStorage.setOrCreate<PatrolRoute[]>(PK_ROUTES, this.repo.routes);
    AppStorage.setOrCreate<PatrolPoint[]>(PK_POINTS, this.repo.points);
    AppStorage.setOrCreate<PatrolCheckin[]>(PK_CHECKINS, this.repo.checkins);
    AppStorage.setOrCreate<string>(PK_SELECTED_ROUTE, this.selectedRouteId);
    AppStorage.setOrCreate<string>(PK_DASHBOARD_PERIOD, this.period);
    this.emitDashboard();
    this.emitHome();
  }

  private emitDashboard(): void {
    const data: DashboardData = DashboardCalculator.compute(
      this.repo.records,
      this.repo.risks,
      this.repo.points,
      this.repo.checkins,
      this.period,
      this.selectedRouteId,
    );
    AppStorage.setOrCreate<DashboardData>(PK_DASHBOARD, data);
  }

  private emitHome(): void {
    const summary = DashboardCalculator.homeSummary(
      this.repo.records,
      this.repo.risks,
      this.repo.points,
      this.repo.checkins,
      this.selectedRouteId,
    );
    AppStorage.setOrCreate<ActivityEntry[]>(PK_HOME_ACTIVITY, summary.activity);
    AppStorage.setOrCreate<number>(PK_HOME_PENDING_RISKS, summary.pendingRisksCount);
    AppStorage.setOrCreate<number>(PK_HOME_PATROL_PROGRESS, summary.todayPatrolProgress);
  }

  // ---- Validation ----
  validateRecord(d: RecordDraft): ValidationResult {
    if (d.title.trim().length === 0) {
      return { valid: false, message: '请填写记录标题' };
    }
    if (d.datetime <= 0) {
      return { valid: false, message: '请选择发生时间' };
    }
    if (d.photos.length > 3) {
      return { valid: false, message: '最多上传 3 张照片' };
    }
    return { valid: true, message: '' };
  }

  validateRisk(d: RiskDraft): ValidationResult {
    if (d.title.trim().length === 0) {
      return { valid: false, message: '请填写隐患标题' };
    }
    if (d.deadline <= 0) {
      return { valid: false, message: '请选择整改截止日期' };
    }
    return { valid: true, message: '' };
  }

  validateCheckin(d: CheckinDraft): ValidationResult {
    if (d.pointId.length === 0) {
      return { valid: false, message: '缺少巡检点' };
    }
    return { valid: true, message: '' };
  }

  validateContact(d: ContactDraft): ValidationResult {
    if (d.name.trim().length === 0) {
      return { valid: false, message: '请填写联系人姓名' };
    }
    if (d.phone.trim().length === 0) {
      return { valid: false, message: '请填写电话号码' };
    }
    const digits: string = d.phone.replace(/[^0-9]/g, '');
    if (!/^\d{3,}$/.test(digits)) {
      return { valid: false, message: '电话号码格式不正确' };
    }
    return { valid: true, message: '' };
  }

  // ---- Records ----
  saveRecord(d: RecordDraft, id?: string): ValidationResult {
    const v: ValidationResult = this.validateRecord(d);
    if (!v.valid) {
      return v;
    }
    const now: number = Date.now();
    if (id !== undefined && id.length > 0) {
      const ex: SafetyRecord | null = this.repo.getRecord(id);
      if (ex === null) {
        return { valid: false, message: '记录不存在' };
      }
      this.repo.updateRecord(id, {
        id: ex.id,
        title: d.title,
        category: d.category,
        datetime: d.datetime,
        location: d.location,
        description: d.description,
        photos: d.photos,
        createdAt: ex.createdAt,
        updatedAt: now,
      });
    } else {
      this.repo.addRecord({
        id: IdGen.next('rec'),
        title: d.title,
        category: d.category,
        datetime: d.datetime,
        location: d.location,
        description: d.description,
        photos: d.photos,
        createdAt: now,
        updatedAt: now,
      });
    }
    void this.repo.persistRecords();
    AppStorage.setOrCreate<SafetyRecord[]>(PK_RECORDS, this.repo.records);
    this.emitDashboard();
    this.emitHome();
    return { valid: true, message: '已保存' };
  }

  deleteRecord(id: string): void {
    this.repo.deleteRecord(id);
    void this.repo.persistRecords();
    AppStorage.setOrCreate<SafetyRecord[]>(PK_RECORDS, this.repo.records);
    this.emitDashboard();
    this.emitHome();
  }

  // ---- Risks ----
  saveRisk(d: RiskDraft, id?: string): ValidationResult {
    const v: ValidationResult = this.validateRisk(d);
    if (!v.valid) {
      return v;
    }
    const now: number = Date.now();
    if (id !== undefined && id.length > 0) {
      const ex: RiskItem | null = this.repo.getRisk(id);
      if (ex === null) {
        return { valid: false, message: '隐患不存在' };
      }
      this.repo.updateRisk(id, {
        id: ex.id,
        title: d.title,
        level: d.level,
        location: d.location,
        description: d.description,
        assignee: d.assignee,
        deadline: d.deadline,
        status: ex.status,
        progress: ex.progress,
        progressNote: ex.progressNote,
        photos: d.photos,
        createdAt: ex.createdAt,
        updatedAt: now,
      });
    } else {
      this.repo.addRisk({
        id: IdGen.next('risk'),
        title: d.title,
        level: d.level,
        location: d.location,
        description: d.description,
        assignee: d.assignee,
        deadline: d.deadline,
        status: 'pending',
        progress: 0,
        progressNote: '',
        photos: d.photos,
        createdAt: now,
        updatedAt: now,
      });
    }
    void this.repo.persistRisks();
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    this.emitDashboard();
    this.emitHome();
    return { valid: true, message: '已保存' };
  }

  updateRiskProgress(id: string, progress: number, note: string): ValidationResult {
    const ex: RiskItem | null = this.repo.getRisk(id);
    if (ex === null) {
      return { valid: false, message: '隐患不存在' };
    }
    const clamped: number = Math.max(0, Math.min(100, Math.round(progress)));
    let status: string = ex.status;
    if (status !== 'closed') {
      if (clamped >= 100) {
        status = 'awaitingAcceptance';
      } else if (clamped > 0 && status === 'pending') {
        status = 'inProgress';
      }
    }
    this.repo.updateRisk(id, {
      id: ex.id,
      title: ex.title,
      level: ex.level,
      location: ex.location,
      description: ex.description,
      assignee: ex.assignee,
      deadline: ex.deadline,
      status: status,
      progress: clamped,
      progressNote: note,
      photos: ex.photos,
      createdAt: ex.createdAt,
      updatedAt: Date.now(),
    });
    void this.repo.persistRisks();
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    this.emitDashboard();
    this.emitHome();
    return { valid: true, message: '进度已更新' };
  }

  acceptRisk(id: string): ValidationResult {
    const ex: RiskItem | null = this.repo.getRisk(id);
    if (ex === null) {
      return { valid: false, message: '隐患不存在' };
    }
    if (ex.status !== 'awaitingAcceptance') {
      return { valid: false, message: '当前状态不可验收' };
    }
    this.repo.updateRisk(id, {
      id: ex.id,
      title: ex.title,
      level: ex.level,
      location: ex.location,
      description: ex.description,
      assignee: ex.assignee,
      deadline: ex.deadline,
      status: 'closed',
      progress: 100,
      progressNote: ex.progressNote,
      photos: ex.photos,
      createdAt: ex.createdAt,
      updatedAt: Date.now(),
    });
    void this.repo.persistRisks();
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    this.emitDashboard();
    this.emitHome();
    return { valid: true, message: '已验收关闭' };
  }

  deleteRisk(id: string): void {
    this.repo.deleteRisk(id);
    void this.repo.persistRisks();
    AppStorage.setOrCreate<RiskItem[]>(PK_RISKS, this.repo.risks);
    this.emitDashboard();
    this.emitHome();
  }

  // ---- Patrol ----
  pointsOfSelectedRoute(): PatrolPoint[] {
    return this.repo.pointsOfRoute(this.selectedRouteId);
  }

  pointById(pointId: string): PatrolPoint | null {
    for (let i = 0; i < this.repo.points.length; i++) {
      if (this.repo.points[i].id === pointId) {
        return this.repo.points[i];
      }
    }
    return null;
  }

  selectPatrolRoute(routeId: string): void {
    this.selectedRouteId = routeId;
    AppStorage.setOrCreate<string>(PK_SELECTED_ROUTE, this.selectedRouteId);
    this.emitDashboard();
    this.emitHome();
  }

  submitCheckin(d: CheckinDraft): ValidationResult {
    const v: ValidationResult = this.validateCheckin(d);
    if (!v.valid) {
      return v;
    }
    const now: number = Date.now();
    this.repo.addCheckin({
      id: IdGen.next('chk'),
      pointId: d.pointId,
      routeId: d.routeId,
      time: now,
      location: d.location,
      note: d.note,
      isAbnormal: d.isAbnormal,
      photos: d.photos,
      createdAt: now,
    });
    void this.repo.persistCheckins();
    AppStorage.setOrCreate<PatrolCheckin[]>(PK_CHECKINS, this.repo.checkins);
    this.emitDashboard();
    this.emitHome();
    return { valid: true, message: '打卡成功' };
  }

  // ---- Contacts ----
  saveContact(d: ContactDraft, id?: string): ValidationResult {
    const v: ValidationResult = this.validateContact(d);
    if (!v.valid) {
      return v;
    }
    if (id !== undefined && id.length > 0) {
      const ex: EmergencyContact | null = this.repo.getContact(id);
      if (ex === null) {
        return { valid: false, message: '联系人不存在' };
      }
      this.repo.updateContact(id, {
        id: ex.id,
        name: d.name,
        role: d.role,
        group: d.group,
        phone: d.phone,
      });
    } else {
      this.repo.addContact({
        id: IdGen.next('ct'),
        name: d.name,
        role: d.role,
        group: d.group,
        phone: d.phone,
      });
    }
    void this.repo.persistContacts();
    AppStorage.setOrCreate<EmergencyContact[]>(PK_CONTACTS, this.repo.contacts);
    return { valid: true, message: '已保存' };
  }

  deleteContact(id: string): void {
    this.repo.deleteContact(id);
    void this.repo.persistContacts();
    AppStorage.setOrCreate<EmergencyContact[]>(PK_CONTACTS, this.repo.contacts);
  }

  async dialContact(phone: string): Promise<boolean> {
    if (this.ctx === null) {
      return false;
    }
    return PhoneService.dial(this.ctx, phone);
  }

  // ---- Dashboard ----
  changeDashboardPeriod(period: string): void {
    this.period = period === 'month' ? 'month' : 'week';
    AppStorage.setOrCreate<string>(PK_DASHBOARD_PERIOD, this.period);
    this.emitDashboard();
  }

  // ---- Notification stub (Non-Goal in 1.0) ----
  openNotifications(): string {
    return '暂无新通知';
  }

  // ---- Option lists for pickers (visual phase) ----
  recordCategoryOptions(): string[] {
    return RECORD_CATEGORY_OPTIONS.slice();
  }

  contactGroupOptions(): ContactGroup[] {
    return CONTACT_GROUP_OPTIONS.slice();
  }
}

