// Domain models and enums for 平安扣 Pinankou.
// Pure data contracts shared by services, controller, and (later) pages.
// No UI, no layout — headless logic only.

export type RecordCategory =
  | 'fire'        // 消防
  | 'equipment'   // 设施设备
  | 'environment' // 环境卫生
  | 'personnel'   // 人员行为
  | 'other';      // 其他

export type RiskLevel = 'low' | 'medium' | 'high' | 'critical';

export type RiskStatus = 'pending' | 'inProgress' | 'awaitingAcceptance' | 'closed';

export type ContactGroup = 'fire' | 'medical' | 'security' | 'management' | 'other';

export interface SafetyRecord {
  id: string;
  title: string;
  category: RecordCategory;
  datetime: number;   // ms timestamp of the observed event
  location: string;
  description: string;
  photos: string[];   // up to 3 uris
  createdAt: number;  // ms
  updatedAt: number;  // ms
}

export interface RiskItem {
  id: string;
  title: string;
  level: RiskLevel;
  location: string;
  description: string;
  assignee: string;
  deadline: number;     // ms timestamp
  status: RiskStatus;
  progress: number;     // 0..100
  progressNote: string;
  photos: string[];
  createdAt: number;
  updatedAt: number;
}

export interface PatrolPoint {
  id: string;
  routeId: string;
  name: string;
  location: string;
  order: number;
}

export interface PatrolRoute {
  id: string;
  name: string;
  pointIds: string[];
}

export interface PatrolCheckin {
  id: string;
  pointId: string;
  routeId: string;
  time: number;         // ms timestamp of the check-in
  location: string;
  note: string;
  isAbnormal: boolean;
  photos: string[];
  createdAt: number;
}

export interface EmergencyContact {
  id: string;
  name: string;
  role: string;
  group: ContactGroup;
  phone: string;
}

// Drafts used by form surfaces before validation + persistence.
export interface RecordDraft {
  title: string;
  category: RecordCategory;
  datetime: number;
  location: string;
  description: string;
  photos: string[];
}

export interface RiskDraft {
  title: string;
  level: RiskLevel;
  location: string;
  description: string;
  assignee: string;
  deadline: number;
  photos: string[];
}

export interface CheckinDraft {
  pointId: string;
  routeId: string;
  location: string;
  note: string;
  isAbnormal: boolean;
  photos: string[];
}

