// Display helpers for 平安扣 Pinankou.
// ArkTS strict mode forbids untyped object literals, so enum->label/color maps
// are exposed as helper functions (switch-based) rather than Record literals.
// Pure logic — consumed by pages during visual integration.

import {
  RecordCategory,
  RiskLevel,
  RiskStatus,
  ContactGroup,
} from './Models';

export function recordCategoryLabel(cat: RecordCategory): string {
  switch (cat) {
    case 'fire': return '消防';
    case 'equipment': return '设施设备';
    case 'environment': return '环境卫生';
    case 'personnel': return '人员行为';
    case 'other': return '其他';
    default: return '其他';
  }
}

export function riskLevelLabel(level: RiskLevel): string {
  switch (level) {
    case 'low': return '低';
    case 'medium': return '中';
    case 'high': return '高';
    case 'critical': return '重大';
    default: return '低';
  }
}

export function riskLevelWeight(level: RiskLevel): number {
  switch (level) {
    case 'low': return 1;
    case 'medium': return 2;
    case 'high': return 3;
    case 'critical': return 4;
    default: return 1;
  }
}

