// Pure derivation of dashboard + home summary metrics over repository snapshots.
// No side effects, no UI.

import {
  SafetyRecord,
  RiskItem,
  PatrolPoint,
  PatrolCheckin,
  EmergencyContact,
  DashboardData,
  DashboardTrendPoint,
  ActivityEntry,
  RiskStatus,
} from '../model/Models';
import { RISK_LEVEL_WEIGHT } from '../model/Labels';

const DAY_MS: number = 24 * 60 * 60 * 1000;
const LEVEL_KEYS: string[] = ['low', 'medium', 'high', 'critical'];

export class DashboardCalculator {
  static compute(
    records: SafetyRecord[],
    risks: RiskItem[],
    points: PatrolPoint[],
    checkins: PatrolCheckin[],
    period: string,
    selectedRouteId: string,
  ): DashboardData {
    const span: number = period === 'month' ? 30 : 7;
    const now: number = Date.now();
    const startOfDay: number = Math.floor(now / DAY_MS) * DAY_MS;

    // Patrol completion (today, scoped to selected route or all points).
    const routePointIds: string[] = selectedRouteId.length > 0
      ? points
        .filter((p: PatrolPoint): boolean => p.routeId === selectedRouteId)
        .map((p: PatrolPoint): string => p.id)
      : points.map((p: PatrolPoint): string => p.id);

    const checkedToday: Set<string> = new Set<string>();
    for (let i = 0; i < checkins.length; i++) {
      const c: PatrolCheckin = checkins[i];
      if (c.time >= startOfDay && c.time < startOfDay + DAY_MS) {
        checkedToday.add(c.pointId);
      }
    }
    let doneCount: number = 0;
    for (let i = 0; i < routePointIds.length; i++) {
      if (checkedToday.has(routePointIds[i])) {
        doneCount++;
      }
    }
    const patrolCompletionRate: number = routePointIds.length > 0
      ? Math.round((doneCount / routePointIds.length) * 100)
      : 0;

    // Risk resolution rate.
    let closedCount: number = 0;
    for (let i = 0; i < risks.length; i++) {
      if (risks[i].status === 'closed') {
        closedCount++;
      }
    }
    const riskResolutionRate: number = risks.length > 0
      ? Math.round((closedCount / risks.length) * 100)
      : 0;

    // Overdue risks (open + past deadline).
    let overdueRisksCount: number = 0;
    for (let i = 0; i < risks.length; i++) {
      const r: RiskItem = risks[i];
      if (r.status !== 'closed' && r.deadline > 0 && r.deadline < now) {
        overdueRisksCount++;
      }
    }

    // Trend over the span.
    const trend: DashboardTrendPoint[] = [];
    for (let back = span - 1; back >= 0; back--) {
      const dayStart: number = startOfDay - back * DAY_MS;
      const dayEnd: number = dayStart + DAY_MS;
      let recCount: number = 0;
      for (let i = 0; i < records.length; i++) {
        if (records[i].createdAt >= dayStart && records[i].createdAt < dayEnd) {
          recCount++;
        }
      }
      let riskCount: number = 0;
      for (let i = 0; i < risks.length; i++) {
        if (risks[i].createdAt >= dayStart && risks[i].createdAt < dayEnd) {
          riskCount++;
        }
      }
      const d: Date = new Date(dayStart);
      trend.push({
        dateLabel: `${d.getMonth() + 1}-${d.getDate()}`,
        records: recCount,
        risks: riskCount,
      });
    }

    // Risk level distribution.
    const dist: Record<string, number> = { low: 0, medium: 0, high: 0, critical: 0 };
    for (let i = 0; i < risks.length; i++) {
      const lvl: string = risks[i].level;
      dist[lvl] = dist[lvl] + 1;
    }

    // Top open risks: by level weight, then recency.
    const open: RiskItem[] = risks
      .filter((r: RiskItem): boolean => r.status !== 'closed');
    open.sort((a: RiskItem, b: RiskItem): number => {
      const w: number = RISK_LEVEL_WEIGHT[b.level] - RISK_LEVEL_WEIGHT[a.level];
      if (w !== 0) {
        return w;
      }
      return b.createdAt - a.createdAt;
    });
    const topRisks: RiskItem[] = open.slice(0, 5);

    return {
      period: period,
      patrolCompletionRate: patrolCompletionRate,
      riskResolutionRate: riskResolutionRate,
      overdueRisksCount: overdueRisksCount,
      totalRecordsCount: records.length,
      trend: trend,
      riskLevelDistribution: dist,
      topRisks: topRisks,
    };
  }

  static homeSummary(
    records: SafetyRecord[],
    risks: RiskItem[],
    points: PatrolPoint[],
    checkins: PatrolCheckin[],
    selectedRouteId: string,
  ): { pendingRisksCount: number; todayPatrolProgress: number; activity: ActivityEntry[] } {
    let pending: number = 0;
    for (let i = 0; i < risks.length; i++) {
      if (risks[i].status !== 'closed') {
        pending++;
      }
    }

    const routePointIds: string[] = selectedRouteId.length > 0
      ? points
        .filter((p: PatrolPoint): boolean => p.routeId === selectedRouteId)
        .map((p: PatrolPoint): string => p.id)
      : points.map((p: PatrolPoint): string => p.id);
    const now: number = Date.now();
    const startOfDay: number = Math.floor(now / DAY_MS) * DAY_MS;
    const checked: Set<string> = new Set<string>();
    for (let i = 0; i < checkins.length; i++) {
      const c: PatrolCheckin = checkins[i];
      if (c.time >= startOfDay && c.time < startOfDay + DAY_MS) {
        checked.add(c.pointId);
      }
    }
    let done: number = 0;
    for (let i = 0; i < routePointIds.length; i++) {
      if (checked.has(routePointIds[i])) {
        done++;
      }
    }
    const progress: number = routePointIds.length > 0
      ? Math.round((done / routePointIds.length) * 100)
      : 0;

    const activity: ActivityEntry[] = DashboardCalculator.mergeActivity(records, risks, checkins);
    return {
      pendingRisksCount: pending,
      todayPatrolProgress: progress,
      activity: activity,
    };
  }

  private static mergeActivity(
    records: SafetyRecord[],
    risks: RiskItem[],
    checkins: PatrolCheckin[],
  ): ActivityEntry[] {
    const entries: ActivityEntry[] = [];
    for (let i = 0; i < records.length; i++) {
      const r: SafetyRecord = records[i];
      entries.push({
        id: r.id,
        kind: 'record',
        title: r.title,
        subtitle: r.location.length > 0 ? r.location : '安全事项',
        timestamp: r.createdAt,
      });
    }
    for (let i = 0; i < risks.length; i++) {
      const r: RiskItem = risks[i];
      entries.push({
        id: r.id,
        kind: 'risk',
        title: r.title,
        subtitle: r.location.length > 0 ? r.location : '风险隐患',
        timestamp: r.createdAt,
      });
    }
    for (let i = 0; i < checkins.length; i++) {
      const c: PatrolCheckin = checkins[i];
      entries.push({
        id: c.id,
        kind: 'checkin',
        title: c.isAbnormal ? '异常巡检打卡' : '巡检打卡',
        subtitle: c.location.length > 0 ? c.location : '巡检',
        timestamp: c.createdAt,
      });
    }
    entries.sort((a: ActivityEntry, b: ActivityEntry): number => b.timestamp - a.timestamp);
    return entries.slice(0, 20);
  }

  // Group contacts by group key, preserving CONTACT_GROUP_OPTIONS order.
  static groupContacts(
    contacts: EmergencyContact[],
    order: string[],
  ): { group: string; items: EmergencyContact[] }[] {
    const buckets: Map<string, EmergencyContact[]> = new Map<string, EmergencyContact[]>();
    for (let i = 0; i < order.length; i++) {
      buckets.set(order[i], []);
    }
    for (let i = 0; i < contacts.length; i++) {
      const c: EmergencyContact = contacts[i];
      if (!buckets.has(c.group)) {
        buckets.set(c.group, []);
      }
      buckets.get(c.group)!.push(c);
    }
    const out: { group: string; items: EmergencyContact[] }[] = [];
    for (let i = 0; i < order.length; i++) {
      const items: EmergencyContact[] = buckets.get(order[i]) ?? [];
      if (items.length > 0) {
        out.push({ group: order[i], items: items });
      }
    }
    return out;
  }

  static levelKeys(): string[] {
    return LEVEL_KEYS.slice();
  }

  static isOpenStatus(status: RiskStatus): boolean {
    return status !== 'closed';
  }
}

